import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import WazirxCloneScreen from "@screens/wazirx";
import ContactUs from "@components/common/move-forward";
import Faq from "@components/common/faq";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const WazirxCloneScript = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "WazirX Clone Script", link: null },
  ];
  const wazirxFaqData = [
    {
      question: "Is the WazirX clone script customizable?",
      answer: "Yes, WazirX clone scripts are highly customizable.",
    },
    {
      question: "Can I launch my cryptocurrency exchange like WazirX?",
      answer:
        "Yes, our WazirX clone script enables you to quickly launch your WazirX-like exchange platform.",
    },
    {
      question:
        "How long does launching a crypto exchange using your WazirX clone script take?",
      answer:
        "Launch time typically ranges from weeks to a few months based on your requirements.",
    },
    {
      question:
        "Which cryptocurrencies are supported by your WazirX clone script?",
      answer:
        "The script supports various cryptocurrencies, including Bitcoin, Ethereum, and more.",
    },
    {
      question: "How secure is the WazirX clone script?",
      answer:
        "Our WazirX clone script prioritizes security, ensuring robust protection for users and their assets.",
    },
    {
      question: "Does your WazirX clone script support mobile devices?",
      answer: "Yes, it's typically designed to be mobile-friendly.",
    },
    {
      question: "What advantages does your WazirX clone script offer?",
      answer:
        "Our clone script provides a fast and cost-effective solution with all essential features.",
    },
    {
      question: "Do I need technical expertise to use the clone script?",
      answer:
        "No, our clone script is designed to be user-friendly, requiring only basic technical knowledge to operate.",
    },
  ];

  const { data } = props;
  const fileUrl =
    data?.wazirxClongImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;

  // console.log("data", data);
  const validData = data?.allMetaJson?.nodes[0];
  // console.log("validData", validData);
  const location = useLocation();

  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "A WazirX clone script is a pre-designed crypto exchange with sections in trading, wallet, and administration to start your own exchange.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1567",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is a WazirX Clone Script?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A WazirX Clone Script is an off-the-shelf cryptocurrency exchange code, which mimics the main functionality of WazirX and allows you to start your currency exchange including wallets, order matching, and administration functions.",
            },
          },
          {
            "@type": "Question",
            name: "Is the platform customizable?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes, the platform can be customised. The design, functionality, trading partners, charges, payment integrations, and other options can be adjusted to your business requirements.",
            },
          },
          {
            "@type": "Question",
            name: "Does it support spot, P2P, and margin trading?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes, the majority of WazirX clone scripts have spot and P2P trade as default and margin trade may be added depending on the package or customization.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      />
      <BreadCrumbV2 items={breadcrumbLinks} />
      <WazirxCloneScreen db={db} />;
      <Faq faqData={wazirxFaqData} />
      <ContactUs db={db} />
    </Layout_v2>
  );
};

